49: func (c createOrgMigratedKVStoreEntries) Exec(sess *xorm.Session, mg *migrator.Migrator) error {
50: 	var anyOrg int64 = 0
51: 	migrated := kvStoreV1Entry{
52: 		OrgID:     &anyOrg,
53: 		Namespace: &KVNamespace,
54: 		Key:       &migratedKey,
55: 	}
56: 	has, err := sess.Table("kv_store").Get(&migrated)
57: 	if err != nil {
58: 		return err
59: 	}
60: 
61: 	if !has {
62: 		mg.Logger.Debug("No migrated status in kvstore, nothing to set")
63: 		return nil
64: 	}
65: 
66: 	// Rename old entry key and value.
67: 	val := Legacy
68: 	if migrated.Value == "true" {
69: 		val = UnifiedAlerting
70: 	}
71: 	if _, err := sess.Table("kv_store").Where("id = ?", migrated.ID).Update(&kvStoreV1Entry{
72: 		Key:   &typeKey,
73: 		Value: string(val),
74: 	}); err != nil {
75: 		mg.Logger.Error("failed to rename org migrated status in kvstore", "err", err)
76: 		return err
77: 	}
78: 
79: 	var orgs []struct {
80: 		ID int64 `xorm:"id"`
81: 	}
82: 	if err := sess.SQL("select id from org").Find(&orgs); err != nil {
83: 		return err
84: 	}
85: 
86: 	if len(orgs) == 0 {
87: 		mg.Logger.Debug("no orgs, nothing to set in kvstore")
88: 		return nil
89: 	}
90: 
91: 	for _, org := range orgs {
92: 		id := org.ID
93: 		entry := kvStoreV1Entry{
94: 			OrgID:     &id,
95: 			Namespace: &KVNamespace,
96: 			Key:       &migratedKey,
97: 			Value:     migrated.Value,
98: 			Created:   migrated.Created,
99: 			Updated:   migrated.Updated,
100: 		}
101: 		if _, errCreate := sess.Table("kv_store").Insert(&entry); errCreate != nil {
102: 			mg.Logger.Error("failed to insert org migration status to kvstore", "err", errCreate)
103: 			return fmt.Errorf("failed to insert org migration status to kvstore: %w", errCreate)
104: 		}
105: 	}
106: 
107: 	return nil
108: }
