118: func (c addBackAnyOrgMigratedEntry) Exec(sess *xorm.Session, mg *migrator.Migrator) error {
119: 	var anyOrg int64 = 0
120: 	migratedEntries := make([]kvStoreV1Entry, 0)
121: 	cond := kvStoreV1Entry{
122: 		Namespace: &KVNamespace,
123: 		Key:       &migratedKey,
124: 	}
125: 	err := sess.Table("kv_store").Find(&migratedEntries, &cond)
126: 	if err != nil {
127: 		return err
128: 	}
129: 
130: 	if len(migratedEntries) == 0 {
131: 		mg.Logger.Debug("No migrated orgs in kvstore, nothing to set")
132: 		return nil
133: 	}
134: 
135: 	migratedStatus := "false"
136: 	for _, migrated := range migratedEntries {
137: 		if migrated.OrgID != nil && *migrated.OrgID == anyOrg {
138: 			mg.Logger.Debug("Already have migrated status for orgid=0, nothing to set")
139: 			return nil
140: 		}
141: 		// All org entries should have the same value. If, somehow, they don't, we set it to true if any orgs are migrated.
142: 		// This is because assuming an org is migrated when it isn't is less bad as force_migration check exists.
143: 		if migrated.Value == "true" {
144: 			migratedStatus = "true"
145: 		}
146: 	}
147: 
148: 	now := time.Now()
149: 	if _, err := sess.Table("kv_store").Insert(&kvStoreV1Entry{
150: 		OrgID:     &anyOrg,
151: 		Namespace: &KVNamespace,
152: 		Key:       &migratedKey,
153: 		Value:     migratedStatus,
154: 		Created:   now,
155: 		Updated:   now,
156: 	}); err != nil {
157: 		mg.Logger.Error("failed to insert orgid=0 migrated status in kvstore", "err", err)
158: 		return err
159: 	}
160: 	return nil
161: }
